const { exec } = require('child_process');

module.exports = async function (context, req) {
    const inputFilename = req.body.inputFilename;
    const outputFormat = req.body.outputFormat;

    if (!inputFilename || !outputFormat) {
        context.res = {
            status: 400,
            body: 'Please provide both inputFilename and outputFormat.'
        };
        return;
    }

    const outputFilename = inputFilename.replace(/\.[^/.]+$/, `.${outputFormat}`);
    const command = `libreoffice --headless --convert-to ${outputFormat} ${inputFilename} --outdir ${__dirname}`;

    exec(command, (error, stdout, stderr) => {
        if (error) {
            context.res = {
                status: 500,
                body: `Conversion failed: ${stderr}`
            };
            return;
        }
        context.res = {
            status: 200,
            body: `File converted successfully. Output file: ${outputFilename}`
        };
    });
};